import React, { useState, useEffect } from 'react';
import { useTheme } from '../../contexts/ThemeContext';
import { useData } from '../../contexts/DataContext';
import TextAnimation from '../common/TextAnimation';
import ProjectCard from './ProjectCard';
import styles from './Projects.module.css';

/**
 * Projects component displays a collection of project cards with filtering options.
 * It features interactive animations and responsive design.
 */
const Projects = () => {
  const { theme } = useTheme();
  const { projects: projectsData, loading: dataLoading } = useData();
  const [activeFilter, setActiveFilter] = useState('all');
  const [animatedProjects, setAnimatedProjects] = useState([]);
  const [isVisible, setIsVisible] = useState(false);

  // Get unique categories from projects data
  const categories = projectsData 
    ? ['all', ...new Set(
      projectsData.flatMap(project => 
        // Check if technologies array exists, if not return 'other'
        project.technologies ? project.technologies.map(tech => tech.toLowerCase()) : ['other']
      )
    )]
    : ['all'];

  // Observer to detect when the section enters viewport
  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );

    const projectsSection = document.getElementById('projects-section');
    if (projectsSection) {
      observer.observe(projectsSection);
    }

    return () => {
      if (projectsSection) {
        observer.disconnect();
      }
    };
  }, []);

  // Animate projects gradually
  useEffect(() => {
    if (isVisible && projectsData && !dataLoading) {
      // Stagger the animations for each project card
      const animationDelay = 150; // ms between each project animation
      
      const timer = setTimeout(() => {
        const interval = setInterval(() => {
          setAnimatedProjects(prev => {
            if (prev.length >= projectsData.length) {
              clearInterval(interval);
              return prev;
            }
            return [...prev, projectsData[prev.length]];
          });
        }, animationDelay);
        
        return () => clearInterval(interval);
      }, 500); // Initial delay before starting animations
      
      return () => clearTimeout(timer);
    }
  }, [isVisible, projectsData, dataLoading]);

  // Filter projects based on active category
  const filteredProjects = activeFilter === 'all'
    ? animatedProjects
    : animatedProjects.filter(project => 
      project.technologies && project.technologies
        .some(tech => tech.toLowerCase() === activeFilter.toLowerCase())
    );

  if (dataLoading) {
    return (
      <section 
        id='projects-section' 
        className={styles.projects}
        data-testid='projects-component'
      >
        <div className={styles.container}>
          <TextAnimation 
            text='Featured Projects' 
            className={styles.title}
            animation='fadeIn'
          />
          <div className={styles.loading}>
            <p>Loading projects...</p>
          </div>
        </div>
      </section>
    );
  }

  return (
    <section 
      id='projects-section' 
      className={styles.projects}
      data-testid='projects-component'
    >
      <div className={styles.container}>
        <TextAnimation 
          text='Featured Projects' 
          className={styles.title}
          animation='fadeIn'
        />
        
        {/* Filter buttons */}
        <div className={styles.filters}>
          {categories.map((category) => (
            <button
              key={category}
              className={`${styles.filterButton} ${activeFilter === category ? styles.active : ''}`}
              onClick={() => setActiveFilter(category)}
              data-testid={`filter-${category}`}
            >
              {category.charAt(0).toUpperCase() + category.slice(1)}
            </button>
          ))}
        </div>
        
        {/* Projects grid */}
        <div className={styles.projectsGrid}>
          {filteredProjects.map((project, index) => (
            <div 
              key={project.id} 
              className={styles.projectCard}
              style={{
                animationDelay: `${index * 0.15}s`,
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? 'translateY(0)' : 'translateY(30px)'
              }}
            >
              <ProjectCard project={project} />
            </div>
          ))}
        </div>
        
        {/* Show a message if no projects match the filter */}
        {filteredProjects.length === 0 && (
          <div className={styles.noProjects}>
            <p>No projects found for this category.</p>
          </div>
        )}
        
        {/* Call to action button */}
        {projectsData && projectsData.length > 6 && (
          <div className={styles.viewMoreContainer}>
            <a 
              href="/#projects-section" 
              className={styles.viewMoreButton}
              data-testid='view-more-button'
            >
              View All Projects
            </a>
          </div>
        )}
      </div>
    </section>
  );
};

export default Projects;
